import '../Barra/Barra.css'
import AppBar from '@mui/material/AppBar';
import Box from '@mui/material/Box';
import Toolbar from '@mui/material/Toolbar';
import Typography from '@mui/material/Typography';
import Button from '@mui/material/Button';
import IconButton from '@mui/material/IconButton';
import MenuIcon from '@mui/icons-material/Menu';
import Link from "@mui/material/Link"
import { Hidden } from '@mui/material';
import { useState } from 'react';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
import ExpandLessIcon from '@mui/icons-material/ExpandLess';

export default function Barra() {
  const [seeMore, setSeeMore] = useState(false)
  const showOpciones  = seeMore ? 'barra verMas' : 'barra verMenos'

  const handleClick = () => {
    setSeeMore(!seeMore)
    console.log(seeMore)  
  }

  return (
    <Box sx={{ flexGrow: 1}}>
      <AppBar className='barra' sx={{bgcolor:"#111"}} position="static">
        <Toolbar>
          <IconButton
            size="large"
            edge="start"
            color="inherit"
            aria-label="menu"
            sx={{ mr: 2 }}
          >
            <MenuIcon/>
          </IconButton>
          <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
            <Link sx={{ml:0}} href="#" variant='h5' color="inherit" underline="none">NombreDeMarca</Link>
          </Typography>
          <Hidden mdDown>
            
            <a><Link href="#" color="inherit" underline='hover' variant='body2'>Quiénes somos?</Link></a>
            <a><Link href="#" color="inherit" underline='hover' variant='body2'>Nuestro trabajo</Link></a>
            <a><Link href="#" color="inherit" underline='hover' variant='body2'>Preguntas frecuentes</Link></a>
            <Button color="inherit">Iniciar sesión</Button>
            <Button color="inherit">Registrarse</Button>
          </Hidden>
          <a onClick={handleClick}>
            {seeMore == true ? <ExpandLessIcon className={"noMostrar"}/> : <ExpandMoreIcon className={"mostrar"}/>}
          </a>
        </Toolbar>
        <div className={showOpciones}>
          <a><Link href="#" color="inherit" underline='hover' variant='body2'>Quiénes somos?</Link></a>
          <a><Link href="#" color="inherit" underline='hover' variant='body2'>Nuestro trabajo</Link></a>
          <a><Link href="#" color="inherit" underline='hover' variant='body2'>Preguntas frecuentes</Link></a>
        </div>
      </AppBar>
    </Box>
  );
}
